mapper.sql:
s.is_deleted = 0 AND s.settle_status IN (1, 2, 3)
AND s.settle_date >= #{q.dateFrom}
AND s.settle_date <= #{q.dateTo}
AND s.customer_uuid = #{q.customerUuid}
AND s.settle_type = #{q.settleType}
AND s.is_invoice = #{q.isInvoice}

r.is_deleted = 0 AND r.record_status = 1
AND s.is_deleted = 0 AND s.settle_status IN (1, 2, 3)
AND r.receive_date >= #{q.dateFrom}
AND r.receive_date < DATE_ADD(#{q.dateTo}, INTERVAL 1 DAY)
AND s.customer_uuid = #{q.customerUuid}
AND s.settle_type = #{q.settleType}
AND s.is_invoice = #{q.isInvoice}

d.is_deleted = 0 AND d.delivery_status IN (1, 2)
AND d.delivery_date >= #{q.dateFrom}
AND d.delivery_date <= #{q.dateTo}
AND d.customer_uuid = #{q.customerUuid}
